const express = require('express');
const redis = require('redis');
const twilio = require('twilio');

const app = express();
const client = redis.createClient();

app.use(express.json());

// Generate 6-digit codes with Math.random()
function generateCode() {
  let code = '';
  for (let i = 0; i < 6; i++) {
    code += Math.floor(Math.random() * 10);
  }
  return code;
}

// Send SMS with Twilio
function sendSms(phoneNumber, message) {
  const accountSid = 'YOUR_TWILIO_ACCOUNT_SID';
  const authToken = 'YOUR_TWILIO_AUTH_TOKEN';
  const client = new twilio(accountSid, authToken);
  client.messages.create({
    from: '+1234567890',
    body: message,
    to: phoneNumber
  });
}

// Store code in Redis with 10-minute expiration
function storeCode(phoneNumber, code) {
  client.setex(`${phoneNumber}:code`, 600, code);
}

// Accept code via POST and grant access if it matches
app.post('/verify', (req, res) => {
  const phoneNumber = req.body.phoneNumber;
  const code = req.body.code;
  const storedCode = client.get(`${phoneNumber}:code`);
  if (storedCode === code) {
    // Grant access
    res.sendStatus(200);
  } else {
    // Deny access and increment attempt counter
    const attempts = parseInt(client.get(`${phoneNumber}:attempts`) || 0);
    if (attempts >= 10) {
      // Lockout user after 10 attempts
      res.sendStatus(429);
    } else {
      client.setex(`${phoneNumber}:attempts`, 60, attempts + 1);
      res.sendStatus(403);
    }
  }
});

// Start server
